     9| * source of truth for "which message wins" when the same turn exists both
    10| * locally and remotely — the logic that decides whether the chat survives a
    11| * reload, route change, logout/login, or a transient remote-read failure.
    12| */
    13|
    14|/** Minimal structural shape needed to merge/dedupe owner-chat messages. */
    15|export interface MergeableOwnerMessage {
    16|  id: string;
    17|  conversationId: string;
    18|  senderUserId: string | null;
    19|  senderRole: string;
    20|  body: string | null;
    21|  attachmentUrl: string | null;
    22|  attachmentName: string | null;
    23|  createdAt: string;
    24|}
    25|
