    29|
    30|/** Exact-identity signature (conversation + sender + body + attachment + createdAt). */
    31|export function buildOwnerMessageSignature(message: MergeableOwnerMessage): string {
    32|  return [
    33|    normalizeMessageComparisonValue(message.conversationId),
    34|    normalizeMessageComparisonValue(message.senderUserId),
    35|    normalizeMessageComparisonValue(message.senderRole),
    36|    normalizeMessageComparisonValue(message.body),
    37|    normalizeMessageComparisonValue(message.attachmentUrl),
    38|    normalizeMessageComparisonValue(message.attachmentName),
    39|    normalizeMessageComparisonValue(message.createdAt),
    40|  ].join('::');
    41|}
    42|
    43|/**
    44| * Looser content key (conversation + role + body) used to recognise the SAME
    45| * logical turn after it has been re-persisted remotely with a fresh server id
    46| * and timestamp. Returns null for attachment-only messages (no body) so two
    47| * different uploads are never collapsed.
    48| */
    49|export function buildOwnerMessageContentKey(message: MergeableOwnerMessage): string | null {
    50|  const body = normalizeMessageComparisonValue(message.body);
    51|  if (body.length === 0) {
    52|    return null;
    53|  }
    54|  return [
    55|    normalizeMessageComparisonValue(message.conversationId),
    56|    normalizeMessageComparisonValue(message.senderRole),
    57|    body,
    58|  ].join('::');
    59|}
    60|
    61|function sortByCreatedAtAscending<T extends MergeableOwnerMessage>(messages: T[]): T[] {
    62|  return [...messages].sort(
    63|    (left, right) => new Date(left.createdAt).getTime() - new Date(right.createdAt).getTime(),
    64|  );
    65|}
    66|
    67|/**
    68| * Merge remote (authoritative) and local (shadow/fallback) owner messages.
    69| *
    70| * Rules:
    71| * - Remote rows always win.
    72| * - A local row is dropped if its exact signature already exists remotely
    73| *   (true duplicate), OR if a remote row shares its content key — i.e. the same
    74| *   text turn that was successfully re-persisted remotely with a new server
    75| *   timestamp. This prevents the "message shows twice after reload" artifact.
    76| * - Local-only rows (never persisted remotely, e.g. offline/auth-degraded sends)
    77| *   are preserved so the conversation never loses a turn.
    78| */
    79|export function mergeOwnerMessages<T extends MergeableOwnerMessage>(
    80|  remoteMessages: T[],
    81|  localMessages: T[],
    82|): T[] {
