    92|    const contentKey = buildOwnerMessageContentKey(message);
    93|    if (contentKey) {
    94|      remoteContentKeys.add(contentKey);
    95|    }
    96|  }
    97|
    98|  for (const message of localMessages) {
    99|    const signature = buildOwnerMessageSignature(message);
   100|    if (merged.has(signature)) {
   101|      continue;
   102|    }
   103|    const contentKey = buildOwnerMessageContentKey(message);
   104|    if (contentKey && remoteContentKeys.has(contentKey)) {
   105|      // Stale local copy of a turn that is already persisted remotely.
   106|      continue;
   107|    }
   108|    merged.set(signature, message);
   109|  }
   110|
   111|  return sortByCreatedAtAscending(Array.from(merged.values()));
